const input = $input.first().json;
const action = input.action;
if (!action) return [{ json: { error: 'Parameter "action" is required (read or send).' } }];

// Fetch credentials from template_credentials
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.email-imap-smtp&select=cred_key,cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0) {
  return [{ json: { error: 'Email credentials not configured. Use add_credential to set them up.' } }];
}

const credMap = {};
for (const c of creds) credMap[c.cred_key] = c.cred_value;

if (!credMap.email_user || !credMap.email_password) {
  return [{ json: { error: 'email_user and email_password must be configured.' } }];
}

const BRIDGE_URL = 'http://email-bridge:3100';

if (action === 'read') {
  if (!credMap.imap_host) {
    return [{ json: { error: 'imap_host credential not configured.' } }];
  }

  const body = {
    host: credMap.imap_host,
    port: Number(credMap.imap_port || 993),
    user: credMap.email_user,
    password: credMap.email_password,
    folder: input.folder || 'INBOX',
    limit: Number(input.limit || 10)
  };
  if (input.since) body.since = input.since;
  if (input.before) body.before = input.before;
  if (input.unseen) body.unseen = true;
  if (input.from) body.from = input.from;

  try {
    const data = await helpers.httpRequest({
      method: 'POST',
      url: BRIDGE_URL + '/read-emails',
      body,
      headers: { 'Content-Type': 'application/json' }
    });

    if (data.error) return [{ json: { error: data.error } }];

    let result = 'Emails (' + data.emails.length + ' of ' + data.total + ' total):\n\n';
    for (const e of data.emails) {
      result += '- **' + e.subject + '**\n';
      result += '  From: ' + e.from + ' | ' + (e.date || '') + '\n';
      if (e.text) result += '  ' + e.text.replace(/\n/g, ' ').trim() + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to read emails: ' + err.message } }];
  }

} else if (action === 'send') {
  if (!credMap.smtp_host) {
    return [{ json: { error: 'smtp_host credential not configured.' } }];
  }
  if (!input.to || !input.subject) {
    return [{ json: { error: 'Parameters "to" and "subject" are required for sending.' } }];
  }

  const body = {
    host: credMap.smtp_host,
    port: Number(credMap.smtp_port || 587),
    user: credMap.email_user,
    password: credMap.email_password,
    to: input.to,
    subject: input.subject,
    body: input.body || ''
  };
  if (input.html) body.html = input.html;

  try {
    const data = await helpers.httpRequest({
      method: 'POST',
      url: BRIDGE_URL + '/send-email',
      body,
      headers: { 'Content-Type': 'application/json' }
    });

    if (data.error) return [{ json: { error: data.error } }];
    return [{ json: { result: 'Email sent successfully to ' + input.to + ' (ID: ' + data.messageId + ')' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to send email: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use "read" or "send".' } }];
}
